// Android — Gradle flavors
android {
  flavorDimensions += "environment"
  productFlavors {
    create("dev") {
      dimension = "environment"
      applicationIdSuffix = ".dev"
      versionNameSuffix = "-dev"
      buildConfigField("String", "API_BASE", "\"https://dev.api/\"")
    }
    create("staging") {
      dimension = "environment"
      applicationIdSuffix = ".staging"
      buildConfigField("String", "API_BASE", "\"https://staging.api/\"")
    }
    create("prod") {
      dimension = "environment"
      buildConfigField("String", "API_BASE", "\"https://api.example.com/\"")
    }
  }
}

// Per-flavor source sets
// app/src/dev/res/values/strings.xml
// app/src/dev/AndroidManifest.xml — add a debug-only Activity

// Build a specific variant
// ./gradlew assembleDevDebug
// ./gradlew bundleProdRelease

// iOS — xcconfig per environment
// Configs/Dev.xcconfig:
//   API_BASE = https:/$()/dev.api
//   PRODUCT_BUNDLE_IDENTIFIER = com.example.app.dev
// Configs/Prod.xcconfig:
//   API_BASE = https:/$()/api.example.com
//   PRODUCT_BUNDLE_IDENTIFIER = com.example.app
//
// Build setting reads $(API_BASE); Info.plist contains <string>$(API_BASE)</string>
// Schemes pick which xcconfig to use.
//
// xcodebuild -scheme MyApp -configuration Dev build
// xcodebuild -scheme MyApp -configuration Prod archive
